def get_ciphertext_model():
    """
    Reconstruct and return a scikit-learn model from an embedded, base64-encoded compressed blob.

    Security note:
      This uses pickle-compatible loading. Only use if you trust the source.
    """
    import base64
    import pickle as _p
    import lzma as _lz; _decomp = _lz.decompress
    _blob_b64 = ""
    _raw = _decomp(base64.b64decode(_blob_b64))
    model = _p.loads(_raw)
    return model


def get_model(device: str = "cpu", dtype: str | None = None):
    """
    Return a TorchScript model loaded from an embedded, base64-encoded compressed blob.
    Self-contained: no need for the original Python class.

    Args:
        device: Where to map the model (e.g., "cpu", "cuda", "cuda:0").
        dtype: Optional dtype to convert parameters/buffers to (e.g., "float32", "float16").
    """
    import base64, io, torch
    import zlib as _z; _decomp = _z.decompress
    _blob_b64 = ""
    _raw = _decomp(base64.b64decode(_blob_b64))
    buf = io.BytesIO(_raw)
    m = torch.jit.load(buf, map_location=device)
    if dtype is not None:
        dt = getattr(torch, dtype) if isinstance(dtype, str) else dtype
        for p in m.parameters():
            p.data = p.data.to(dt)
        for b in m.buffers():
            b.data = b.data.to(dt)
    m.eval()
    return m


IDX_TO_LABEL = {0: 'agent', 1: 'boots', 2: 'box', 3: 'coin', 4: 'core', 5: 'door_locked', 6: 'enemy', 7: 'exit', 8: 'floor', 9: 'ghost', 10: 'hazard', 11: 'key', 12: 'shield', 13: 'wall'}


from collections import deque, Counter

import os
import heapq
import pandas as pd
import numpy as np
import torch

from grid_universe.gym_env import Observation, Action, BaseAction
from grid_universe.levels.grid import Level
from grid_universe.levels.convert import to_state, from_state
from grid_universe.step import step
from grid_universe.objectives import (
    default_objective_fn,
    exit_objective_fn,
    OBJECTIVE_FN_REGISTRY,
)
from grid_universe.moves import MOVE_FN_REGISTRY, default_move_fn
from grid_universe.levels.entity_spec import EntitySpec

from grid_universe.levels.factories import (
    create_floor, create_agent, create_wall, create_coin, create_exit,
    create_key, create_door, create_hazard, create_monster, create_box,
    create_phasing_effect, create_immunity_effect, create_speed_effect, create_core
)

from grid_universe.components.properties import AppearanceName, MovingAxis


from PIL import Image

class Node:
    def __init__(self, priority, state, path, cost):
        self.priority = priority
        self.state = state
        self.path = path
        self.cost = cost

    def __lt__(self, other):
        return self.priority < other.priority


class Agent:
    def __init__(self):
        self.plan = deque() # stores Action
        self.visited = {}
        self.obj_model = None
        self.vectorizer = None
        self.tile_prototypes = {}

        self.decoder()

        self.tile_model = get_model(device="cpu")
        self.tile_model.eval()

        self.gym_to_engine = {
            Action.UP: BaseAction.UP,
            Action.DOWN: BaseAction.DOWN,
            Action.LEFT: BaseAction.LEFT,
            Action.RIGHT: BaseAction.RIGHT,
            Action.PICK_UP: BaseAction.PICK_UP,
            Action.USE_KEY: BaseAction.USE_KEY,
            Action.WAIT: BaseAction.WAIT,
        }
        self.engine_to_gym = {v: k for k, v in self.gym_to_engine.items()}

        self.cached_level = None
        self.cached_seed = None

    # ========================= Main step ========================= #

    def step(self, state):
        # Follow existing plan if we have one
        if self.plan:
            return self.plan.popleft()

        # Otherwise re-plan from current state
        engine_state = self.convert_to_state(state)
        if not engine_state:
            return Action.WAIT

        self.visited.clear()
        self.plan = self.astar(engine_state)

        if not self.plan:
            return Action.WAIT
        return self.plan.popleft()

    # ===================== Perception / Parsing ================== #

    def convert_to_state(self, state):
        # Task 1 and 2: Level -> State
        if isinstance(state, Level):
            new_state = to_state(state)
            if state.message is not None:
                level = from_state(new_state)
                level.objective_fn = self.decode_objective(new_state, state.message)
                new_state = to_state(level)
            return new_state

        # Task 3 and 4: Observation -> Level -> State
        if "image" in state and "info" in state:
            info = state["info"]
            config = info["config"]
            level = self.parse_image_to_level(state)
            if not level:
                return None

            # Task 3
            obj_name = config.get("objective_fn", "default_objective_fn")
            if obj_name in OBJECTIVE_FN_REGISTRY:
                level.objective_fn = OBJECTIVE_FN_REGISTRY[obj_name]
            else:
                level.objective_fn = default_objective_fn

            move_name = config.get("move_fn", "default_move_fn")
            if move_name in MOVE_FN_REGISTRY:
                level.move_fn = MOVE_FN_REGISTRY[move_name]
            else:
                level.move_fn = MOVE_FN_REGISTRY["default"]

            engine_state = to_state(level)
            return engine_state

        return None
    
    # IMAGE 
    def classify_tile(self, tile_arr, return_probs = False):
        if self.tile_model is None:
            if return_probs:
                # uniform-ish dummy
                num_classes = len(IDX_TO_LABEL)
                return np.ones(num_classes, dtype=np.float32) / num_classes
            return "floor"

        # ensure uint8
        if tile_arr.dtype != np.uint8:
            tile_arr = tile_arr.astype(np.uint8)

        # RGBA -> RGB
        if tile_arr.shape[2] == 4:
            tile_arr = tile_arr[:, :, :3]

        img = Image.fromarray(tile_arr, mode='RGB')
        img = img.resize((32, 32), Image.NEAREST)

        arr = np.asarray(img, dtype=np.float32) / 255.0
        arr = np.transpose(arr, (2, 0, 1))
        x = torch.from_numpy(arr).unsqueeze(0)

        with torch.no_grad():
            logits = self.tile_model(x)
            probs = torch.softmax(logits, dim=1)[0].cpu().numpy()

        if return_probs:
            return probs

        pred = int(probs.argmax())
        return IDX_TO_LABEL.get(pred, "floor")


    def parse_image_to_level(self, obs):
        if "image" not in obs or "info" not in obs:
            return None

        img = obs["image"]
        info = obs["info"]
        cfg = info.get("config", {})

        width = int(cfg.get("width", 0))
        height = int(cfg.get("height", 0))
        if img is None or width <= 0 or height <= 0:
            return None

        H, W = img.shape[0], img.shape[1]
        if H <= 0 or W <= 0:
            return None

        tile_h = H // height
        tile_w = W // width
        if tile_h <= 0 or tile_w <= 0:
            return None

        if img.ndim != 3 or img.shape[2] < 3:
            return None
        img_rgb = img[:, :, :3]

        level = Level(
            width=width,
            height=height,
            move_fn=cfg.get('move_fn', default_move_fn),
            objective_fn=cfg.get('objective_fn', default_objective_fn),
            seed=cfg.get("seed", 0),
            win=False,
            lose=False,
            message=info.get("message", ""),
            turn_limit=cfg.get("turn_limit", -1),
        )

        counts = Counter()

        # Thresholds
        CONF_STRONG = 0.35
        EXIT_FALLBACK = 0.15

        # Label index lookup
        label_to_idx = {v: k for k, v in IDX_TO_LABEL.items()}
        EXIT_IDX = label_to_idx.get("exit", None)
        AGENT_IDX = label_to_idx.get("agent", None)
        def detect_arrow_direction_white(tile_rgb):
            h, w = tile_rgb.shape[:2]
            
            # Extract center region where arrow is drawn
            center = tile_rgb[h//4:3*h//4, w//4:3*w//4]
            
            # Find white pixels (RGB > 220)
            is_white = np.all(center >= 220, axis=2)
            
            if not np.any(is_white):
                return None
            
            # Find center of mass of white pixels
            white_y, white_x = np.where(is_white)
            arrow_y = np.mean(white_y)
            arrow_x = np.mean(white_x)
            
            # Compare to center
            center_y = center.shape[0] / 2
            center_x = center.shape[1] / 2
            
            dy = arrow_y - center_y
            dx = arrow_x - center_x
            
            # Determine direction
            if abs(dy) > abs(dx):
                return 'up' if dy > 1 else 'down'
            else:
                return 'left' if dx > 1 else 'right'

        def arrow_direction_to_movement_properties(direction):
            if direction == 'down':
                return MovingAxis.VERTICAL, 1
            elif direction == 'up':
                return MovingAxis.VERTICAL, -1
            elif direction == 'right':
                return MovingAxis.HORIZONTAL, 1
            elif direction == 'left':
                return MovingAxis.HORIZONTAL, -1
            return MovingAxis.VERTICAL, 1  # default
        
        # Tracking
        has_exit = False
        strong_agent_candidates = []
        all_agent_candidates = []
        exit_candidates = []
        placed_label = [["floor" for _ in range(width)] for _ in range(height)]
        key_candidates = []
        door_candidates = []
        core_candidates = []
        enemy_candidates = []
        shield_candidates = []
        ghost_candidates = []
        boots_candidates = []
        hazard_candidates = []

        for gy in range(height):
            y0 = gy * tile_h
            y1 = (gy + 1) * tile_h
            for gx in range(width):
                x0 = gx * tile_w
                x1 = (gx + 1) * tile_w

                tile = img_rgb[y0:y1, x0:x1]
                probs = self.classify_tile(tile, return_probs=True)
                pred_idx = int(probs.argmax())
                pred_prob = float(probs[pred_idx])
                raw_label = IDX_TO_LABEL.get(pred_idx, "floor")

                def add_candidate(class_name, store):
                    idx = label_to_idx.get(class_name)
                    if idx is not None and probs[idx] > 0.0:
                        store.append((float(probs[idx]), (gx, gy)))

                add_candidate("key", key_candidates)
                add_candidate("door_locked", door_candidates)
                add_candidate("core", core_candidates)
                add_candidate("enemy", enemy_candidates)
                add_candidate("shield", shield_candidates)
                add_candidate("ghost", ghost_candidates)
                add_candidate("boots", boots_candidates)
                add_candidate("hazard", hazard_candidates)

                if EXIT_IDX is not None and probs[EXIT_IDX] > 0.0:
                    exit_candidates.append((float(probs[EXIT_IDX]), (gx, gy)))
                if AGENT_IDX is not None and probs[AGENT_IDX] > 0.0:
                    all_agent_candidates.append((float(probs[AGENT_IDX]), (gx, gy), raw_label))
                    if probs[AGENT_IDX] >= CONF_STRONG:
                        strong_agent_candidates.append((float(probs[AGENT_IDX]), (gx, gy)))

                label = "floor"
                if pred_prob >= CONF_STRONG:
                    label = raw_label

                counts[label] += 1

                level.add((gx, gy), create_floor())
                placed_label[gy][gx] = "floor"

                if label == "wall":
                    level.add((gx, gy), create_wall())
                    placed_label[gy][gx] = "wall"
                elif label == "exit":
                    level.add((gx, gy), create_exit())
                    placed_label[gy][gx] = "exit"
                    has_exit = True
                elif label == "hazard":
                    level.add((gx, gy), create_hazard(appearance=AppearanceName.SPIKE, damage=2, lethal=False))
                    placed_label[gy][gx] = "hazard"
                elif label == "enemy":
                    arrow_dir = detect_arrow_direction_white(tile)
                    moving_axis, moving_dir = arrow_direction_to_movement_properties(arrow_dir)
                    level.add((gx, gy), create_monster(damage=1, lethal=False, moving_axis=moving_axis, moving_direction=moving_dir, moving_bounce=True, moving_speed=1))
                    placed_label[gy][gx] = "enemy"
                elif label == "key":
                    level.add((gx, gy), create_key(key_id="default"))
                    placed_label[gy][gx] = "key"
                elif label == "door_locked":
                    level.add((gx, gy), create_door(key_id="default"))
                    placed_label[gy][gx] = "door_locked"
                elif label == "coin":
                    level.add((gx, gy), create_coin())
                    placed_label[gy][gx] = "coin"
                elif label == "core":
                    level.add((gx, gy), create_core(required=True))
                    placed_label[gy][gx] = "core"
                elif label == "box":
                    level.add((gx, gy), create_box(pushable=True))
                    placed_label[gy][gx] = "box"
                elif label == "shield":
                    level.add((gx, gy), create_immunity_effect(usage=5))
                    placed_label[gy][gx] = "shield"
                elif label == "ghost":
                    level.add((gx, gy), create_phasing_effect(time=5))
                    placed_label[gy][gx] = "ghost"
                elif label == "boots":
                    level.add((gx, gy), create_speed_effect(multiplier=2, time=5))
                    placed_label[gy][gx] = "boots"

        # Ensure exactly one agent
        agent_pos = None

        if agent_pos is None and strong_agent_candidates:
            # sort by probabilities
            strong_agent_candidates.sort(key=lambda x:-x[0])
            _, (ax, ay) = strong_agent_candidates[0]
            
            # avoid placing on wall or exit
            if placed_label[ay][ax] in ("wall", "exit"):
                placed = False
                for p, (gx, gy) in strong_agent_candidates[1:]:
                    if placed_label[gy][gx] not in ("wall", "exit"):
                        ax, ay = gx, gy
                        placed = True
                        break
            agent_pos = (ax, ay)

        # Place the single agent
        if agent_pos is not None:
            agent_info = info.get('agent')
            health = agent_info.get('health')
            act_health = health.get('health')
            level.add(agent_pos, create_agent(health = act_health))
        else:
            print("parse_image_to_level -- warning: agent_pos is None!")

        return level


    # Task 2 -- DECODERR

    def decoder(self):
        try:
            self.obj_model = get_ciphertext_model()
        except Exception:
            self.obj_model = None

    def decode_objective(self, engine_state, message):
        if not message or self.obj_model is None:
            return default_objective_fn
        
        try:
            label = self.obj_model.predict([message])[0]
        except Exception:
            return default_objective_fn

        return OBJECTIVE_FN_REGISTRY.get(label, default_objective_fn)


    # state representation

    def state_hash(self, state, agent_id):
        # position
        pos = state.position if state.position is not None else {}
        agent_pos = pos.get(agent_id)
        agent_pos_t = (agent_pos.x, agent_pos.y) if agent_pos is not None else None

        # inventories
        inv_keys = ()
        if state.inventory is not None and agent_id in state.inventory:
            inv_obj = state.inventory[agent_id]
            if isinstance(inv_obj, list):
                keys = []
                for item in inv_obj:
                    # EntitySpec(key=...)
                    if hasattr(item, "key") and item.key is not None:
                        keys.append(item.key)
                inv_keys = tuple(sorted(keys))
            elif hasattr(inv_obj, "item_ids") and state.key is not None:
                ks = []
                for item_id in inv_obj.item_ids:
                    kc = state.key.get(item_id)
                    if kc is not None and hasattr(kc, "key_id"):
                        ks.append(kc.key_id)
                inv_keys = tuple(sorted(ks))

        # speed
        speed_vals = ()
        if state.status is not None and agent_id in state.status:
            status_obj = state.status[agent_id]
            if isinstance(status_obj, list):
                rem = []
                for fx in status_obj:
                    if hasattr(fx, "speed") and isinstance(fx.speed, dict):
                        if "remaining" in fx.speed:
                            rem.append(fx.speed["remaining"])
                speed_vals = tuple(sorted(rem))
            elif hasattr(status_obj, "effect_ids") and state.speed is not None:
                rem = []
                for eff_id in status_obj.effect_ids:
                    sc = state.speed.get(eff_id)
                    if sc is not None and hasattr(sc, "remaining"):
                        rem.append(sc.remaining)
                speed_vals = tuple(sorted(rem))

        appearance = state.appearance if state.appearance is not None else {}
        key_ids = set(state.key.keys()) if state.key is not None else set()
        push_ids = set(state.pushable.keys()) if state.pushable is not None else set()
        col_ids = set(state.collectible.keys()) if state.collectible is not None else set()
        leth_ids = set(state.lethal_damage.keys()) if state.lethal_damage is not None else set()
        dmg_ids = set(state.damage.keys()) if state.damage is not None else set()

        dyn = [] # dynamic list
        for eid, p in pos.items():
            if eid == agent_id:
                continue
            if (eid in key_ids or eid in push_ids or eid in col_ids or eid in leth_ids or eid in dmg_ids):
                app = appearance.get(eid)
                name_val = None
                if app is not None and hasattr(app, "name") and app.name is not None:
                    if hasattr(app.name, "value"):
                        name_val = app.name.value
                dyn.append((name_val, p.x, p.y))
        dyn_tup = tuple(sorted(dyn))

        # locked doors
        if state.locked is not None:
            doors = tuple(sorted(state.locked.items()))
        else:
            doors = ()

        return (agent_pos_t, dyn_tup, inv_keys, speed_vals, doors)

    def heuristic(self, state, agent_id):
        pos = state.position if state.position is not None else {}
        agent_pos = pos.get(agent_id)
        if agent_pos is None:
            return 0.0

        exits = state.exit if state.exit is not None else {}
        if not exits:
            return 0.0

        exit_id = next(iter(exits.keys()))
        goal_pos = pos.get(exit_id)
        if goal_pos is None:
            return 0.0

        dist = abs(agent_pos.x - goal_pos.x) + abs(agent_pos.y - goal_pos.y)
        return float(dist * 3)


    # actions!!
    def get_possible_actions(self, state, agent_id):
        pos = state.position if state.position is not None else {}
        agent_pos = pos.get(agent_id)
        if agent_pos is None:
            return [BaseAction.WAIT]

        actions = [
            BaseAction.UP,
            BaseAction.DOWN,
            BaseAction.LEFT,
            BaseAction.RIGHT,
        ]

        # PICK_UP only if something here
        collectibles = (
            set(state.collectible.keys()) if state.collectible is not None else set()
        )
        key_ids = set(state.key.keys()) if state.key is not None else set()
        can_pick = False
        if collectibles or key_ids:
            for eid, p in pos.items():
                if p.x == agent_pos.x and p.y == agent_pos.y:
                    if eid in collectibles or eid in key_ids:
                        can_pick = True
                        break
        if can_pick:
            actions.append(BaseAction.PICK_UP)

        # USE_KEY only if we have a key and at least one locked door
        has_key = False
        if state.inventory is not None and agent_id in state.inventory:
            inv_obj = state.inventory[agent_id]
            if isinstance(inv_obj, list):
                for item in inv_obj:
                    if hasattr(item, "key") and item.key is not None:
                        has_key = True
                        break
            elif hasattr(inv_obj, "item_ids") and state.key is not None:
                for item_id in inv_obj.item_ids:
                    kc = state.key.get(item_id)
                    if kc is not None and hasattr(kc, "key_id"):
                        has_key = True
                        break

        locked_nonempty = state.locked is not None and len(state.locked) > 0
        if has_key and locked_nonempty:
            actions.append(BaseAction.USE_KEY)

        # WAIT as fallback
        actions.append(BaseAction.WAIT)

        return actions

    def baseaction_to_action(self, baseaction):
        return self.engine_to_gym[baseaction]

    # astar search
    def astar(self, initial_state):
        if initial_state.agent is None or len(initial_state.agent) == 0:
            return deque()
        self.visited = {}
        agent_id = next(iter(initial_state.agent.keys()))

        # Initial health
        if initial_state.health is not None and agent_id in initial_state.health:
            hc = initial_state.health[agent_id]
            initial_health = hc.health if hc is not None else 1
        else:
            initial_health = 1

        HEALTH_PENALTY = 50.0
        pq = []

        try:
            start_hash = self.state_hash(initial_state, agent_id)
        except Exception:
            return deque()

        start_node = Node(
            priority=self.heuristic(initial_state, agent_id),
            state=initial_state,
            path=[],
            cost=0.0,
        )
        heapq.heappush(pq, start_node)
        self.visited[start_hash] = 0.0

        while pq:
            current = heapq.heappop(pq)
            state = current.state
            cost = current.cost

            try:
                hsh = self.state_hash(state, agent_id)
            except Exception:
                continue

            # Skip stale nodes
            if cost > self.visited.get(hsh, float("inf")):
                continue

            # Goal
            if state.win:
                return deque(self.baseaction_to_action(a) for a in current.path)

            # Lose / timeout
            if state.lose:
                continue
            if state.turn_limit != -1 and state.turn >= state.turn_limit:
                continue

            # Expand neighbors
            for act in self.get_possible_actions(state, agent_id):
                nxt = step(state, act, agent_id)

                try:
                    nxt_hash = self.state_hash(nxt, agent_id)
                except Exception:
                    continue

                # Score-based cost (higher score → lower cost)
                score = float(nxt.score) if hasattr(nxt, "score") else 0.0
                score_cost = -score

                # Health penalty
                nxt_health = 0
                if nxt.health is not None and agent_id in nxt.health:
                    nxt_hc = nxt.health[agent_id]
                    if nxt_hc is not None:
                        nxt_health = nxt_hc.health
                lost = max(0, initial_health - nxt_health)
                health_cost = lost * HEALTH_PENALTY

                new_cost = score_cost + health_cost

                # Only keep strictly better paths to this hash
                if new_cost >= self.visited.get(nxt_hash, float("inf")):
                    continue

                self.visited[nxt_hash] = new_cost
                new_path = current.path + [act]
                priority = new_cost + self.heuristic(nxt, agent_id)

                heapq.heappush(
                    pq,
                    Node(priority, nxt, new_path, new_cost),
                )

        return deque()
    
